import{c as a,Q as r,j as e,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Natural-Language Agent Harnesses (NLAH)","description":"","frontmatter":{"url":"https://arxiv.org/html/2603.25723v1","title":"Natural-Language Agent Harnesses (NLAH)","date":"2026-03-26T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-26-natural-language-agent-harnesses-nlah.md","filePath":"research/ai-articles/scored/2026-03-26-natural-language-agent-harnesses-nlah.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/scored/2026-03-26-natural-language-agent-harnesses-nlah.md"};function l(o,t,i,d,h,g){return r(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="natural-language-agent-harnesses-nlah" tabindex="-1">Natural-Language Agent Harnesses (NLAH) <a class="header-anchor" href="#natural-language-agent-harnesses-nlah" aria-label="Permalink to &quot;Natural-Language Agent Harnesses (NLAH)&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://arxiv.org/html/2603.25723v1" target="_blank" rel="noreferrer">https://arxiv.org/html/2603.25723v1</a><br><strong>作者</strong>：Linyue Pan 等（清華大學深圳研究生院、哈爾濱工業大學）<br><strong>發表日期</strong>：2026-03-26<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="問題定義" tabindex="-1">問題定義 <a class="header-anchor" href="#問題定義" aria-label="Permalink to &quot;問題定義&quot;">​</a></h3><p>當前 Agent 系統的 harness 邏輯（控制多步驟執行的協調層）被嵌入 controller 程式碼中。這帶來四個問題：</p><ol><li><strong>耦合</strong>：harness 邏輯與執行環境緊密耦合</li><li><strong>不透明</strong>：控制流是隱式的，難以理解或修改</li><li><strong>無法複用</strong>：harness 模式無法跨項目分享或調適</li><li><strong>無法評估</strong>：難以孤立 harness 效果與執行環境或模型效果</li></ol><h3 id="核心貢獻-將-harness-設計當成一等研究對象" tabindex="-1">核心貢獻：將 Harness 設計當成一等研究對象 <a class="header-anchor" href="#核心貢獻-將-harness-設計當成一等研究對象" aria-label="Permalink to &quot;核心貢獻：將 Harness 設計當成一等研究對象&quot;">​</a></h3><p>NLAH 方法：</p><ul><li>將 harness 規格<strong>外化為可編輯的自然語言</strong></li><li>在 harness 和執行環境之間維持<strong>明確的合約（contracts）</strong></li><li>保留確定性的程式碼用於驗證和工具介面</li><li>啟用 harness 效果的系統性評估</li></ul><h3 id="nlah-的七大組件" tabindex="-1">NLAH 的七大組件 <a class="header-anchor" href="#nlah-的七大組件" aria-label="Permalink to &quot;NLAH 的七大組件&quot;">​</a></h3><h4 id="_1-contracts-合約" tabindex="-1">1. Contracts（合約） <a class="header-anchor" href="#_1-contracts-合約" aria-label="Permalink to &quot;1. Contracts（合約）&quot;">​</a></h4><p>執行階段之間的明確協議：</p><ul><li>每個階段的輸入/輸出類型</li><li>成功/失敗條件</li><li>資源預算和逾時</li><li>必要 vs. 可選階段</li></ul><h4 id="_2-roles-角色定義" tabindex="-1">2. Roles（角色定義） <a class="header-anchor" href="#_2-roles-角色定義" aria-label="Permalink to &quot;2. Roles（角色定義）&quot;">​</a></h4><ul><li><strong>Planner role</strong>：決定下一步</li><li><strong>Executor role</strong>：實作決策</li><li><strong>Reviewer role</strong>：驗證結果</li></ul><h4 id="_3-stage-structure-階段結構" tabindex="-1">3. Stage Structure（階段結構） <a class="header-anchor" href="#_3-stage-structure-階段結構" aria-label="Permalink to &quot;3. Stage Structure（階段結構）&quot;">​</a></h4><p>循序或條件執行：規劃 → 行動生成 → 工具執行 → 驗證 → 狀態更新</p><h4 id="_4-adapters-轉接器" tabindex="-1">4. Adapters（轉接器） <a class="header-anchor" href="#_4-adapters-轉接器" aria-label="Permalink to &quot;4. Adapters（轉接器）&quot;">​</a></h4><p>harness 規格與執行環境之間的轉換層；工具輸出與 harness 狀態的橋接。</p><h4 id="_5-scripts-腳本" tabindex="-1">5. Scripts（腳本） <a class="header-anchor" href="#_5-scripts-腳本" aria-label="Permalink to &quot;5. Scripts（腳本）&quot;">​</a></h4><p>確定性邏輯：工具調用、結果解析、狀態持久化、觀測記錄。</p><h4 id="_6-state-semantics-狀態語義" tabindex="-1">6. State Semantics（狀態語義） <a class="header-anchor" href="#_6-state-semantics-狀態語義" aria-label="Permalink to &quot;6. State Semantics（狀態語義）&quot;">​</a></h4><p>指定哪些狀態跨步驟持久化、如何更新、每個角色的可見性規則。</p><h4 id="_7-failure-taxonomies-失敗分類" tabindex="-1">7. Failure Taxonomies（失敗分類） <a class="header-anchor" href="#_7-failure-taxonomies-失敗分類" aria-label="Permalink to &quot;7. Failure Taxonomies（失敗分類）&quot;">​</a></h4><p>可恢復 vs. 不可恢復的失敗；每種失敗類型的重試策略；上升條件。</p><h3 id="intelligent-harness-runtime-ihr" tabindex="-1">Intelligent Harness Runtime（IHR） <a class="header-anchor" href="#intelligent-harness-runtime-ihr" aria-label="Permalink to &quot;Intelligent Harness Runtime（IHR）&quot;">​</a></h3><p>IHR 解釋 NLAH 規格：</p><ul><li><strong>Harness Interpreter</strong>：循環中的 LLM 讀取規格並確定下一個動作</li><li><strong>Backend</strong>：提供工具存取、多 Agent 支援、狀態持久化</li><li><strong>Charter Enforcer</strong>：驗證執行環境行為符合 charter</li></ul><p><strong>關鍵屬性</strong>：自然語言協調高層控制；程式碼強制執行確定性驗證。</p><h3 id="實驗結果" tabindex="-1">實驗結果 <a class="header-anchor" href="#實驗結果" aria-label="Permalink to &quot;實驗結果&quot;">​</a></h3><h4 id="rq1-執行環境的行為重要性" tabindex="-1">RQ1：執行環境的行為重要性 <a class="header-anchor" href="#rq1-執行環境的行為重要性" aria-label="Permalink to &quot;RQ1：執行環境的行為重要性&quot;">​</a></h4><ul><li><strong>發現</strong>：過程指標（token 使用、呼叫次數）在不同條件下大幅變化；任務解決率相對穩定</li><li><strong>意義</strong>：harness 結構有行為意義，不只是「prompt 裝飾」；harness 優化機會在效率，不只在結果</li></ul><h4 id="rq2-模組消融效果" tabindex="-1">RQ2：模組消融效果 <a class="header-anchor" href="#rq2-模組消融效果" aria-label="Permalink to &quot;RQ2：模組消融效果&quot;">​</a></h4><table tabindex="0"><thead><tr><th>模組</th><th>效果</th></tr></thead><tbody><tr><td>Self-evolution</td><td>改善 solve-loop 紀律，減少多餘迭代</td></tr><tr><td>File-backed state</td><td>增強流程結構，減少 context 漂移</td></tr><tr><td>Evidence-backed answering</td><td>提高可審計性，改善錯誤診斷</td></tr><tr><td>Multi-turn memory</td><td>適度改善，依 context 而定</td></tr><tr><td>Retry strategy</td><td>集中在困難案例，簡單任務影響小</td></tr></tbody></table><p>無單一模組提供均勻改善；模組針對特定問題類型。</p><h4 id="rq3-code-to-nlah-遷移" tabindex="-1">RQ3：Code-to-NLAH 遷移 <a class="header-anchor" href="#rq3-code-to-nlah-遷移" aria-label="Permalink to &quot;RQ3：Code-to-NLAH 遷移&quot;">​</a></h4><p><strong>案例研究</strong>：OS-Symphony（原始 code-based agent）</p><ul><li><strong>原始版本</strong>：30.4% 任務成功率</li><li><strong>NLAH 版本</strong>：47.2% 任務成功率</li><li><strong>改善</strong>：<strong>+16.8 個百分點</strong></li></ul><p>關鍵改變：</p><ol><li>可靠性機制從本地螢幕修復 → 持久化執行環境狀態</li><li>控制流抽象為明確的 harness 規格</li><li>啟用跨步驟的系統性狀態持久化</li><li>透過 artifact-backed closure 改善失敗恢復</li></ol><h3 id="自然語言-vs-程式碼的分界" tabindex="-1">自然語言 vs. 程式碼的分界 <a class="header-anchor" href="#自然語言-vs-程式碼的分界" aria-label="Permalink to &quot;自然語言 vs. 程式碼的分界&quot;">​</a></h3><p><strong>NL 適合</strong>：高層協調（角色、階段結構、合約）、控制流規格、委派邊界、錯誤恢復策略</p><p><strong>程式碼必要</strong>：工具調用和結果解析、驗證邏輯和約束、狀態持久化和原子性、效能關鍵操作</p><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>Skills 作為 NLAH 的實例</strong>：cc-workspace 的 SKILL.md 格式（流程步驟、known gotchas、輸出規則）實際上是 NLAH 的自然語言 harness 規格</li><li><strong>File-backed state</strong>：<code>claude-progress.json</code> 的設計與「file-backed state 減少 context 漂移」的發現一致</li><li><strong>Evidence-backed answering</strong>：citation-discipline skill 的設計原理</li><li><strong>Failure Taxonomy</strong>：可在 SKILL.md 的 Known Gotchas 區塊中加入「可恢復/不可恢復」的明確分類</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>NLAH 組件概念可映射到 Skills 設計；但需要翻譯才能直接應用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>將 harness 邏輯外化為可編輯 NL、並維持明確合約是重要的設計突破</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>OS-Symphony 從 30.4% → 47.2% 有明確量化，三個 RQ 均有實驗支撐</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>七大組件有詳細定義，IHR 架構清晰，模組消融有系統性</td></tr><tr><td>E. 泛化性</td><td>7/10</td><td>在 coding 和 OS 任務驗證，但其他領域的遷移性未測試</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.55/10</strong></td><td>7×0.3 + 8×0.2 + 8×0.2 + 8×0.15 + 7×0.15 = 2.1+1.6+1.6+1.2+1.05</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/skill-authoring.md</code>（NLAH 設計模式 → Skill 設計指引）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 skill-authoring.md 中加入「失敗分類（可恢復/不可恢復）」作為 SKILL.md Known Gotchas 的標準格式</li><li>考慮將 NLAH 的 Contracts 概念加入 skill 驗收清單（輸入/輸出類型、成功/失敗條件明確化）</li></ul>',52)])])}const p=a(n,[["render",l]]);export{u as __pageData,p as default};
